elements.content:
flowchart LR
  script["Your Script"] --> engine["JavaScript Engine"]
  subgraph browser["Browser"]
    engine
    dom["Page Model"]
    apis["Browser APIs"]
    screen["Screen"]
  end
  engine -. later .-> dom
  dom -. later .-> screen

  classDef base fill:#171717,stroke:#555,color:#fff,stroke-width:1px;
  classDef focus fill:#f7df1e,stroke:#fff,color:#111,stroke-width:3px;
  classDef muted fill:#242424,stroke:#444,color:#aaa,stroke-width:1px;
  class script,engine focus;
  class dom,apis,screen muted;
  style browser fill:#101010,stroke:#f7df1e,stroke-width:2px,color:#fff;

flowchart LR
  code["JavaScript Code"] --> parser["Read"] --> runner["Run"] --> result["Live Values"]
  subgraph engine["JavaScript Engine"]
    parser
    runner
    result
  end

  classDef base fill:#171717,stroke:#555,color:#fff,stroke-width:1px;
  classDef focus fill:#f7df1e,stroke:#fff,color:#111,stroke-width:3px;
  classDef hot fill:#ff2d95,stroke:#fff,color:#fff,stroke-width:2px;
  class code base;
  class parser,runner focus;
  class result hot;
  style engine fill:#101010,stroke:#f7df1e,stroke-width:2px,color:#fff;

flowchart TB
  engine["JavaScript Engine"] --> dom["DOM"]
  dom --> html["HTML"]
  html --> body["Body"]
  body --> title["Heading Text"]
  body --> button["Button"]
  engine --> editText["Change Text"]
  engine --> editStyle["Change Style"]
  editText --> title
  editStyle --> button

  classDef base fill:#171717,stroke:#555,color:#fff,stroke-width:1px;
  classDef focus fill:#f7df1e,stroke:#fff,color:#111,stroke-width:3px;
  classDef update fill:#00d4ff,stroke:#fff,color:#061116,stroke-width:2px;
  class engine,dom focus;
  class title,button,editText,editStyle update;
  class html,body base;

flowchart LR
  engine["JavaScript Engine"] --> apis
  subgraph apis["Browser APIs"]
    create["Create Elements"]
    fetch["Fetch Data"]
    update["Schedule Updates"]
  end
  create --> dom["DOM Changes"]
  fetch --> dom
  update --> render["Rendering"]
  dom --> render
  render --> screen["Pixels on Screen"]

  classDef base fill:#171717,stroke:#555,color:#fff,stroke-width:1px;
  classDef focus fill:#f7df1e,stroke:#fff,color:#111,stroke-width:3px;
  classDef output fill:#00d4ff,stroke:#fff,color:#061116,stroke-width:2px;
  class engine base;
  class create,fetch,update focus;
  class dom,render,screen output;
  style apis fill:#101010,stroke:#f7df1e,stroke-width:2px,color:#fff;

flowchart LR
  click["Click"] --> queue["Event Queue"]
  timer["Timer"] --> queue
  promise["Promise"] --> micro["Microtask Queue"]
  queue --> loop["Event Loop"]
  micro --> loop
  loop --> stack["Call Stack"]
  stack --> engine["Run JavaScript"]

  classDef base fill:#171717,stroke:#555,color:#fff,stroke-width:1px;
  classDef focus fill:#f7df1e,stroke:#fff,color:#111,stroke-width:3px;
  classDef hot fill:#ff2d95,stroke:#fff,color:#fff,stroke-width:2px;
  class click,timer,promise base;
  class queue,micro focus;
  class loop hot;
  class stack,engine focus;
